{
  "summary": "The paper proposes a method to improve non-parametric language models by incorporating structural locality features into the kNN retrieval distance metric via learnable linear adjustments. Experiments on Wikipedia text and Java source code demonstrate improved perplexity and token prediction accuracy, with stronger gains in domains exhibiting clearer locality structure.",
  "strengths": [
    {
      "point": "Incorporation of structural locality into kNN-LMs improves retrieval relevance and language modeling performance",
      "evidence": "Experiments show consistent perplexity and accuracy gains on Wikipedia and Java datasets, with a ~4.9% relative error reduction on Java source code."
    },
    {
      "point": "Method is lightweight and practical, requiring only a few additional parameters without retraining the base LM",
      "evidence": "Only 5 parameters for Java and 7 for Wikipedia are learned to adjust distances, enabling easy adaptation."
    },
    {
      "point": "Detailed analysis reveals that contextual similarity alone is insufficient to capture structural locality",
      "evidence": "Qualitative and quantitative analyses show locality features provide complementary information, especially for top-ranked neighbors."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient positioning and comparison to prior learned distance metrics in retrieval-augmented LMs",
      "evidence": "No discussion or empirical comparison to established methods like Mahalanobis distance learning or neural re-ranking models."
    },
    {
      "point": "Methodological limitations due to simplistic linear distance adjustment and independence assumptions",
      "evidence": "No ablation studies on linear vs. nonlinear transformations or modeling interactions between locality features."
    },
    {
      "point": "Evaluation lacks stronger baselines, broader metrics, and statistical significance testing",
      "evidence": "Comparisons only against vanilla kNN-LM; no downstream task evaluation, no significance tests, and no ablation on number of neighbors k."
    },
    {
      "point": "Reproducibility concerns due to missing details on validation set construction and optimizer hyperparameters",
      "evidence": "Validation data sampling and Adam optimizer settings are not specified."
    },
    {
      "point": "Limited generalizability and robustness analysis",
      "evidence": "Experiments restricted to two domains; no study on noisy locality annotations or scalability to large, complex datastores."
    },
    {
      "point": "Lack of analysis on retrieval distribution, computational cost, training stability, and failure cases",
      "evidence": "No quantitative analysis of neighbor diversity or bias, no discussion of retrieval efficiency, parameter initialization sensitivity, or error analysis."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed linear distance adjustment compare to more expressive learned metrics or nonlinear transformations?",
      "motivation": "Understanding this would clarify whether the simplicity of the method limits performance or is a design strength."
    },
    {
      "question": "Can the method scale and generalize to domains with large numbers of locality categories or noisy/incomplete hierarchical metadata?",
      "motivation": "This impacts practical applicability and robustness in real-world scenarios."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
